<h1 class="mb-3">Customer Schedule Changes</h1><div class="card"><table class="table mb-0"><thead><tr><th>Job</th><th>Customer</th><th>Request</th><th>Requested Time</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['job_number'])?></td><td><?=e($r['display_name'])?></td><td><?=e($r['request_type'])?><br><small><?=e($r['reason'])?></small></td><td><?=e($r['requested_start'])?></td><td><?=e($r['status'])?></td><td><?php if($r['status']==='pending'):?><form method="post" action="/portal/schedule-changes/<?=$r['id']?>/decide"><?=csrf_field()?><button name="status" value="approved" class="btn btn-sm btn-success">Approve</button> <button name="status" value="declined" class="btn btn-sm btn-outline-danger">Decline</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div>
